const items = $input.all();

if (items.length === 0) {
  return [];
}

const toItem = (value, sourceIndex) => {
  if (!value || typeof value !== 'object' || Array.isArray(value)) {
    throw new Error(`Cliente inválido: cada item precisa ser um objeto JSON.`);
  }

  return {
    json: { ...value },
    pairedItem: { item: sourceIndex },
  };
};

// O HTTP Request do Supabase pode devolver vários itens já separados.
if (items.length > 1) {
  return items.map((item, index) => toItem(item.json, index));
}

// Compatibilidade com respostas em um único item contendo um array JSON.
const first = items[0].json;

if (Array.isArray(first)) {
  return first.map((client) => toItem(client, 0));
}

if (Array.isArray(first?.data)) {
  return first.data.map((client) => toItem(client, 0));
}

// Quando o Supabase devolve apenas um cliente como objeto.
return [toItem(first, 0)];

const c=$json,tz=c.timezone||'America/Sao_Paulo';
const d=x=>Object.fromEntries(new Intl.DateTimeFormat('en-CA',{timeZone:tz,year:'numeric',month:'2-digit',day:'2-digit'}).formatToParts(x).map(p=>[p.type,p.value]));
const iso=x=>{const p=d(x);return `${p.year}-${p.month}-${p.day}`};
const today=iso(new Date()),yesterday=new Date(Date.parse(today+'T00:00:00Z')-86400000).toISOString().slice(0,10);
const arr=(v,f)=>Array.isArray(v)?v:(v?String(v).replace(/[{}]/g,'').split(',').map(x=>x.trim().replace(/^"|"$/g,'')):f);
return [{json:{...c,ad_account_id:String(c.ad_account_id||'').replace(/^act_/i,''),today,yesterday,report_date:today,conversion_action_types:arr(c.conversion_action_types,['lead','onsite_conversion.messaging_conversation_started_7d']),attribution_windows:arr(c.attribution_windows,['7d_click','1d_view'])}}];

const c=$('Preparar cliente').item.json,r=$json||{},payload=r.body??r,status=Number(r.statusCode??r.status??0);
const num=v=>Number.isFinite(Number(v))?Number(v):0;
const rows=Array.isArray(payload.data)?payload.data:[];
const err=r.error||payload.error||(!(status>=200&&status<300)?{message:`Meta ads HTTP ${status||'sem status'}`} :null);

const match=(v,ps)=>(ps||[]).some(p=>{
  p=String(p);
  return p.endsWith('*')?v.startsWith(p.slice(0,-1)):
    p.includes('%')?new RegExp('^'+p.replace(/[.*+?^${}()|[\]\\]/g,'\\$&').replace(/%/g,'.*')+'$').test(v):
    v===p;
});
const sum=(a,ps)=>Array.isArray(a)?a.reduce((s,x)=>s+(match(String(x.action_type||''),ps)?num(x.value):0),0):0;
const first=(a,ps)=>{
  if(!Array.isArray(a))return 0;
  for(const p of ps){
    const x=a.find(z=>match(String(z.action_type||''),[p]));
    if(x)return num(x.value);
  }
  return a[0]?num(a[0].value):0;
};
const metric=row=>{
  row=row||{};
  const spend=num(row.spend);
  const conv=sum(row.actions,c.conversion_action_types);
  const value=sum(row.action_values,['purchase','omni_purchase','offsite_conversion.fb_pixel_purchase','offsite_conversion.custom.%']);
  return {
    spend,
    reach:num(row.reach),
    impressions:num(row.impressions),
    clicks:num(row.clicks),
    ctr:num(row.ctr),
    cpc:num(row.cpc),
    cpm:num(row.cpm),
    conversions:conv,
    cost_per_result:conv?spend/conv:0,
    conversion_value:value,
    roas:first(row.purchase_roas,['omni_purchase','offsite_conversion.fb_pixel_purchase'])||(spend?value/spend:0)
  };
};

const byDate=x=>rows.find(row=>row.date_start===x)||{};
const today=metric(byDate(c.today));
const yesterday=metric(byDate(c.yesterday));

const variation=(a,b)=>{
  if(b===0)return a===0?'0,0%':'novo/sem base';
  const pct=(a-b)/Math.abs(b)*100;
  return `${pct>0?'+':''}${pct.toLocaleString('pt-BR',{minimumFractionDigits:1,maximumFractionDigits:1})}%`;
};
const money=v=>new Intl.NumberFormat('pt-BR',{
  style:'currency',
  currency:String(c.currency||'BRL').trim()
}).format(v);
const number=(v,d=0)=>v.toLocaleString('pt-BR',{minimumFractionDigits:d,maximumFractionDigits:d});
const date=new Date(c.report_date+'T12:00:00Z').toLocaleDateString('pt-BR',{timeZone:'UTC'});

const lines=[
  `💰 *Investimento:* ${money(today.spend)} (${variation(today.spend,yesterday.spend)})`,
  `👥 *Alcance:* ${number(today.reach)} (${variation(today.reach,yesterday.reach)})`,
  `👁️ *Impressões:* ${number(today.impressions)} (${variation(today.impressions,yesterday.impressions)})`,
  `🖱️ *Cliques:* ${number(today.clicks)} (${variation(today.clicks,yesterday.clicks)})`,
  `📈 *CTR:* ${number(today.ctr,2)}% (${variation(today.ctr,yesterday.ctr)})`,
  `💳 *CPC:* ${money(today.cpc)} (${variation(today.cpc,yesterday.cpc)})`,
  `📣 *CPM:* ${money(today.cpm)} (${variation(today.cpm,yesterday.cpm)})`,
  `🎯 *Resultados:* ${number(today.conversions)} (${variation(today.conversions,yesterday.conversions)})`,
  `💵 *Custo por resultado:* ${money(today.cost_per_result)} (${variation(today.cost_per_result,yesterday.cost_per_result)})`,
  `📊 *ROAS:* ${number(today.roas,2)}x (${variation(today.roas,yesterday.roas)})`
];

const destination=String(c.destination||'').replace(/\D/g,'');
const validPhone=/^\d{10,15}$/.test(destination);
const dataValid=!err&&validPhone;

const message=`Olá, *${c.client_name}*! 👋

📊 *Relatório diário de campanhas — ${date}*

${lines.join('\n')}

🔎 _O comparativo foi realizado em relação ao dia anterior._

ℹ️ _Os dados do Meta ads podem receber atualizações posteriores devido à atribuição de conversões._

*R2R Marketing Digital*`;

const empty=today.spend===0&&today.impressions===0&&today.reach===0;

return [{
  json:{
    ...c,
    channel:'whatsapp',
    destination,
    data_valid:dataValid,
    api_error:err
      ? (err.message||JSON.stringify(err))
      : (!validPhone?'Número de WhatsApp inválido; use DDI + DDD + número, somente dígitos.':null),
    metrics_today:today,
    metrics_yesterday:yesterday,
    message,
    delivery_status:empty?'no_activity':'sent'
  }
}];

const base=$('Formatar relatório').item.json;
const response=$json||{};
const status=Number(response.statusCode??response.status??0);
const body=response.body??response;
const providerError=response.error||body?.error;
const hasMessageId=Boolean(body?.key?.id||body?.messageId||body?.id);
const accepted=status>=200&&status<300&&!providerError;

let errorMessage=null;
if(!accepted){
  errorMessage=
    providerError?.message||
    providerError?.error||
    body?.message||
    body?.error||
    `Falha no envio via WhatsApp. HTTP ${status||'sem status'}`;
  if(typeof errorMessage!=='string')errorMessage=JSON.stringify(errorMessage);
}

return [{
  json:{
    ...base,
    channel:'whatsapp',
    delivery_ok:accepted,
    provider_message_id:body?.key?.id||body?.messageId||body?.id||null,
    provider_status:body?.status||null,
    api_error:errorMessage,
    provider_response:body,
    provider_response_has_message_id:hasMessageId
  }
}];
